#pragma once

#include <cuda_runtime.h>
#include <stdint.h>

// Constants from specification
constexpr int NUM_Q_HEADS = 4;
constexpr int NUM_K_HEADS = 4;
constexpr int NUM_V_HEADS = 8;
constexpr int HEAD_SIZE = 128;
constexpr int NUM_SAB_HEADS = 8;  // max(num_q_heads, num_v_heads)

// Data type definitions
using bfloat16_t = __nv_bfloat16;

// Struct for kernel parameters
struct GDNKernelParams {
    // Input tensors
    const bfloat16_t* q;      // [total_seq_len, num_q_heads, head_size]
    const bfloat16_t* k;      // [total_seq_len, num_k_heads, head_size]
    const bfloat16_t* v;      // [total_seq_len, num_v_heads, head_size]
    const float* state;       // [num_seqs, num_v_heads, head_size, head_size]
    const float* A_log;       // [num_v_heads]
    const bfloat16_t* a;      // [total_seq_len, num_v_heads]
    const float* dt_bias;     // [num_v_heads]
    const bfloat16_t* b;      // [total_seq_len, num_v_heads]
    const int64_t* cu_seqlens; // [num_seqs + 1]

    // Output tensors
    bfloat16_t* output;       // [total_seq_len, num_v_heads, head_size]
    float* new_state;         // [num_seqs, num_v_heads, head_size, head_size]

    // Scalar parameters
    float scale;

    // Dimensions
    int total_seq_len;
    int num_seqs;
};

// CUDA kernel declarations
__global__ void gdn_prefill_kernel(
    const bfloat16_t* q,
    const bfloat16_t* k,
    const bfloat16_t* v,
    const float* state,
    const float* A_log,
    const bfloat16_t* a,
    const float* dt_bias,
    const bfloat16_t* b,
    const int64_t* cu_seqlens,
    bfloat16_t* output,
    float* new_state,
    float scale,
    int total_seq_len,
    int num_seqs
);

// Host function declaration
void launch_gdn_prefill(
    const bfloat16_t* q,
    const bfloat16_t* k,
    const bfloat16_t* v,
    const float* state,
    const float* A_log,
    const bfloat16_t* a,
    const float* dt_bias,
    const bfloat16_t* b,
    const int64_t* cu_seqlens,
    bfloat16_t* output,
    float* new_state,
    float scale,
    int total_seq_len,
    int num_seqs
);

#include "kernel.h"
#include <cuda_fp16.h>
#include <cuda_bf16.h>

// A800 optimized block configuration
constexpr int BLOCK_SIZE = 128;
constexpr int WARP_SIZE = 32;
constexpr int WARPS_PER_BLOCK = BLOCK_SIZE / WARP_SIZE;

// Shared memory for state (optimized for A800)
// State is [num_v_heads, head_size, head_size] = [8, 128, 128]
// We'll load one head at a time to fit in shared memory
extern __shared__ float shared_state[];

// Device helper functions
__device__ __forceinline__ float softplus(float x) {
    return logf(1.0f + expf(x));
}

__device__ __forceinline__ float sigmoid(float x) {
    return 1.0f / (1.0f + expf(-x));
}

__device__ __forceinline__ float bf16_to_float(__nv_bfloat16 x) {
    return __bfloat162float(x);
}

__device__ __forceinline__ __nv_bfloat16 float_to_bf16(float x) {
    return __float2bfloat16(x);
}

__device__ __forceinline__ float exp_neg_exp_mul_softplus(
    float A_log, float a_val, float dt_bias_val
) {
    float x = a_val + dt_bias_val;
    float softplus_val = softplus(x);
    float exp_A = expf(A_log);
    return expf(-exp_A * softplus_val);
}

// Kernel implementation optimized for A800
__global__ void gdn_prefill_kernel(
    const bfloat16_t* q,
    const bfloat16_t* k,
    const bfloat16_t* v,
    const float* state,
    const float* A_log,
    const bfloat16_t* a,
    const float* dt_bias,
    const bfloat16_t* b,
    const int64_t* cu_seqlens,
    bfloat16_t* output,
    float* new_state,
    float scale,
    int total_seq_len,
    int num_seqs
) {
    int seq_idx = blockIdx.x;
    int thread_idx = threadIdx.x;

    if (seq_idx >= num_seqs) return;

    int64_t seq_start = cu_seqlens[seq_idx];
    int64_t seq_end = cu_seqlens[seq_idx + 1];
    int seq_len = seq_end - seq_start;

    if (seq_len <= 0) return;

    // Load state for this sequence into shared memory
    // State layout: [num_v_heads, head_size, head_size]
    // We process one head at a time
    float* state_shared = shared_state;

    // Process each value head
    for (int h = 0; h < NUM_V_HEADS; h++) {
        // Load state for head h into shared memory
        // State is [head_size, head_size] for this head
        for (int i = 0; i < HEAD_SIZE; i += BLOCK_SIZE) {
            int row = i + thread_idx;
            if (row < HEAD_SIZE) {
                for (int col = 0; col < HEAD_SIZE; col++) {
                    int state_idx = (seq_idx * NUM_V_HEADS + h) * HEAD_SIZE * HEAD_SIZE + row * HEAD_SIZE + col;
                    state_shared[row * HEAD_SIZE + col] = state[state_idx];
                }
            }
        }
        __syncthreads();

        // Process each timestep in the sequence
        for (int t = 0; t < seq_len; t++) {
            int pos = seq_start + t;

            // Load q, k, v for this position
            // q: [pos, num_q_heads, head_size] -> need to expand to num_v_heads
            // k: [pos, num_k_heads, head_size] -> need to expand to num_v_heads
            // v: [pos, num_v_heads, head_size]

            // Calculate which q/k head to use for this v head
            int q_head = (h * NUM_Q_HEADS) / NUM_V_HEADS;
            int k_head = (h * NUM_K_HEADS) / NUM_V_HEADS;

            // Load q, k, v into registers
            float q_reg[HEAD_SIZE];
            float k_reg[HEAD_SIZE];
            float v_reg[HEAD_SIZE];

            for (int i = 0; i < HEAD_SIZE; i += BLOCK_SIZE) {
                int idx = i + thread_idx;
                if (idx < HEAD_SIZE) {
                    q_reg[idx] = bf16_to_float(q[(pos * NUM_Q_HEADS + q_head) * HEAD_SIZE + idx]);
                    k_reg[idx] = bf16_to_float(k[(pos * NUM_K_HEADS + k_head) * HEAD_SIZE + idx]);
                    v_reg[idx] = bf16_to_float(v[(pos * NUM_V_HEADS + h) * HEAD_SIZE + idx]);
                }
            }
            __syncthreads();

            // Load g and beta parameters
            float a_val = bf16_to_float(a[pos * NUM_V_HEADS + h]);
            float b_val = bf16_to_float(b[pos * NUM_V_HEADS + h]);
            float A_log_val = A_log[h];
            float dt_bias_val = dt_bias[h];

            float g = exp_neg_exp_mul_softplus(A_log_val, a_val, dt_bias_val);
            float beta = sigmoid(b_val);

            // Compute state update
            // state_new = g * state_old + k^T @ (beta * v + (1-beta) * k @ state_old) - k^T @ (k @ state_old)

            // First compute: k @ state_old
            float k_state[HEAD_SIZE];
            for (int i = 0; i < HEAD_SIZE; i++) {
                float sum = 0.0f;
                for (int j = 0; j < HEAD_SIZE; j++) {
                    sum += k_reg[j] * state_shared[j * HEAD_SIZE + i];
                }
                k_state[i] = sum;
            }
            __syncthreads();

            // Compute: beta * v + (1-beta) * k @ state_old
            float new_v[HEAD_SIZE];
            for (int i = 0; i < HEAD_SIZE; i++) {
                new_v[i] = beta * v_reg[i] + (1.0f - beta) * k_state[i];
            }
            __syncthreads();

            // Compute: k^T @ new_v (outer product)
            float state_update[HEAD_SIZE * HEAD_SIZE];
            for (int i = 0; i < HEAD_SIZE; i++) {
                for (int j = 0; j < HEAD_SIZE; j++) {
                    state_update[i * HEAD_SIZE + j] = k_reg[i] * new_v[j];
                }
            }
            __syncthreads();

            // Compute: k^T @ k_state (outer product for removal)
            float state_remove[HEAD_SIZE * HEAD_SIZE];
            for (int i = 0; i < HEAD_SIZE; i++) {
                for (int j = 0; j < HEAD_SIZE; j++) {
                    state_remove[i * HEAD_SIZE + j] = k_reg[i] * k_state[j];
                }
            }
            __syncthreads();

            // Update state: g * state_old - state_remove + state_update
            for (int i = 0; i < HEAD_SIZE; i += BLOCK_SIZE) {
                int row = i + thread_idx;
                if (row < HEAD_SIZE) {
                    for (int col = 0; col < HEAD_SIZE; col++) {
                        state_shared[row * HEAD_SIZE + col] = 
                            g * state_shared[row * HEAD_SIZE + col] - 
                            state_remove[row * HEAD_SIZE + col] + 
                            state_update[row * HEAD_SIZE + col];
                    }
                }
            }
            __syncthreads();

            // Compute output: scale * q @ state_new
            float out_reg[HEAD_SIZE];
            for (int i = 0; i < HEAD_SIZE; i++) {
                float sum = 0.0f;
                for (int j = 0; j < HEAD_SIZE; j++) {
                    sum += q_reg[j] * state_shared[j * HEAD_SIZE + i];
                }
                out_reg[i] = scale * sum;
            }
            __syncthreads();

            // Store output
            for (int i = 0; i < HEAD_SIZE; i += BLOCK_SIZE) {
                int idx = i + thread_idx;
                if (idx < HEAD_SIZE) {
                    output[(pos * NUM_V_HEADS + h) * HEAD_SIZE + idx] = float_to_bf16(out_reg[idx]);
                }
            }
            __syncthreads();
        }

        // Store final state for this head
        for (int i = 0; i < HEAD_SIZE; i += BLOCK_SIZE) {
            int row = i + thread_idx;
            if (row < HEAD_SIZE) {
                for (int col = 0; col < HEAD_SIZE; col++) {
                    int state_idx = (seq_idx * NUM_V_HEADS + h) * HEAD_SIZE * HEAD_SIZE + row * HEAD_SIZE + col;
                    new_state[state_idx] = state_shared[row * HEAD_SIZE + col];
                }
            }
        }
        __syncthreads();
    }
}

// Host function to launch kernel
void launch_gdn_prefill(
    const bfloat16_t* q,
    const bfloat16_t* k,
    const bfloat16_t* v,
    const float* state,
    const float* A_log,
    const bfloat16_t* a,
    const float* dt_bias,
    const bfloat16_t* b,
    const int64_t* cu_seqlens,
    bfloat16_t* output,
    float* new_state,
    float scale,
    int total_seq_len,
    int num_seqs
) {
    // Calculate shared memory size
    // We need HEAD_SIZE * HEAD_SIZE floats for state
    size_t shared_mem_size = HEAD_SIZE * HEAD_SIZE * sizeof(float);

    // Launch configuration optimized for A800
    dim3 grid(num_seqs);
    dim3 block(BLOCK_SIZE);

    // Launch kernel with shared memory
    gdn_prefill_kernel<<<grid, block, shared_mem_size>>>(
        q, k, v, state, A_log, a, dt_bias, b, cu_seqlens,
        output, new_state, scale, total_seq_len, num_seqs
    );

    // Check for kernel launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        printf("CUDA kernel launch error: %s\n", cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include "kernel.h"

#include <cmath>
#include <stdexcept>
#include <vector>

// Helper function to validate tensor properties
void validate_tensor(const torch::Tensor& tensor, const std::string& name, 
                     torch::DType expected_dtype, int64_t expected_dim) {
    if (!tensor.is_cuda()) {
        throw std::runtime_error(name + " must be on CUDA device");
    }
    if (tensor.dtype() != expected_dtype) {
        throw std::runtime_error(name + " must have dtype " + 
                                 torch::str(expected_dtype) + 
                                 " but got " + torch::str(tensor.dtype()));
    }
    if (tensor.dim() != expected_dim) {
        throw std::runtime_error(name + " must have " + std::to_string(expected_dim) + 
                                 " dimensions but got " + std::to_string(tensor.dim()));
    }
}

// Main run function
std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor state,
    torch::Tensor A_log,
    torch::Tensor a,
    torch::Tensor dt_bias,
    torch::Tensor b,
    torch::Tensor cu_seqlens,
    torch::Tensor scale
) {
    // Validate input tensors
    validate_tensor(q, "q", torch::kBFloat16, 3);
    validate_tensor(k, "k", torch::kBFloat16, 3);
    validate_tensor(v, "v", torch::kBFloat16, 3);
    validate_tensor(state, "state", torch::kFloat32, 4);
    validate_tensor(A_log, "A_log", torch::kFloat32, 1);
    validate_tensor(a, "a", torch::kBFloat16, 2);
    validate_tensor(dt_bias, "dt_bias", torch::kFloat32, 1);
    validate_tensor(b, "b", torch::kBFloat16, 2);
    validate_tensor(cu_seqlens, "cu_seqlens", torch::kInt64, 1);

    // Validate shapes
    int64_t total_seq_len = q.size(0);
    int64_t num_q_heads = q.size(1);
    int64_t head_size = q.size(2);
    int64_t num_k_heads = k.size(1);
    int64_t num_v_heads = v.size(1);
    int64_t num_seqs = cu_seqlens.size(0) - 1;

    // Validate constants from specification
    if (num_q_heads != NUM_Q_HEADS) {
        throw std::runtime_error("num_q_heads must be " + std::to_string(NUM_Q_HEADS));
    }
    if (num_k_heads != NUM_K_HEADS) {
        throw std::runtime_error("num_k_heads must be " + std::to_string(NUM_K_HEADS));
    }
    if (num_v_heads != NUM_V_HEADS) {
        throw std::runtime_error("num_v_heads must be " + std::to_string(NUM_V_HEADS));
    }
    if (head_size != HEAD_SIZE) {
        throw std::runtime_error("head_size must be " + std::to_string(HEAD_SIZE));
    }
    if (state.size(0) != num_seqs) {
        throw std::runtime_error("state num_seqs must match cu_seqlens");
    }
    if (state.size(1) != NUM_V_HEADS) {
        throw std::runtime_error("state num_v_heads must be " + std::to_string(NUM_V_HEADS));
    }
    if (state.size(2) != HEAD_SIZE || state.size(3) != HEAD_SIZE) {
        throw std::runtime_error("state head dimensions must be " + std::to_string(HEAD_SIZE));
    }
    if (A_log.size(0) != NUM_V_HEADS) {
        throw std::runtime_error("A_log size must be " + std::to_string(NUM_V_HEADS));
    }
    if (a.size(0) != total_seq_len || a.size(1) != NUM_V_HEADS) {
        throw std::runtime_error("a shape must be [" + std::to_string(total_seq_len) + 
                                 ", " + std::to_string(NUM_V_HEADS) + "]");
    }
    if (dt_bias.size(0) != NUM_V_HEADS) {
        throw std::runtime_error("dt_bias size must be " + std::to_string(NUM_V_HEADS));
    }
    if (b.size(0) != total_seq_len || b.size(1) != NUM_V_HEADS) {
        throw std::runtime_error("b shape must be [" + std::to_string(total_seq_len) + 
                                 ", " + std::to_string(NUM_V_HEADS) + "]");
    }

    // Calculate scale if not provided or zero
    float scale_val = 0.0f;
    if (scale.numel() > 0) {
        scale_val = scale.item<float>();
    }
    if (scale_val == 0.0f) {
        scale_val = 1.0f / std::sqrt(static_cast<float>(HEAD_SIZE));
    }

    // Create output tensors
    torch::Tensor output = torch::empty(
        {total_seq_len, NUM_V_HEADS, HEAD_SIZE},
        torch::TensorOptions().dtype(torch::kBFloat16).device(torch::kCUDA)
    );

    torch::Tensor new_state = torch::empty(
        {num_seqs, NUM_V_HEADS, HEAD_SIZE, HEAD_SIZE},
        torch::TensorOptions().dtype(torch::kFloat32).device(torch::kCUDA)
    );

    // Get raw pointers
    const bfloat16_t* q_ptr = q.data_ptr<bfloat16_t>();
    const bfloat16_t* k_ptr = k.data_ptr<bfloat16_t>();
    const bfloat16_t* v_ptr = v.data_ptr<bfloat16_t>();
    const float* state_ptr = state.data_ptr<float>();
    const float* A_log_ptr = A_log.data_ptr<float>();
    const bfloat16_t* a_ptr = a.data_ptr<bfloat16_t>();
    const float* dt_bias_ptr = dt_bias.data_ptr<float>();
    const bfloat16_t* b_ptr = b.data_ptr<bfloat16_t>();
    const int64_t* cu_seqlens_ptr = cu_seqlens.data_ptr<int64_t>();
    bfloat16_t* output_ptr = output.data_ptr<bfloat16_t>();
    float* new_state_ptr = new_state.data_ptr<float>();

    // Launch kernel
    launch_gdn_prefill(
        q_ptr, k_ptr, v_ptr, state_ptr, A_log_ptr, a_ptr, dt_bias_ptr, b_ptr,
        cu_seqlens_ptr, output_ptr, new_state_ptr, scale_val,
        static_cast<int>(total_seq_len), static_cast<int>(num_seqs)
    );

    // Synchronize and check for errors
    cudaError_t err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        throw std::runtime_error("CUDA execution error: " + std::string(cudaGetErrorString(err)));
    }

    return {output, new_state};
}

// Pybind11 module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "GDN Prefill Kernel for A800 GPU";
    m.def("run", &run, "Execute GDN prefill operation");
}
